## иҜ·жұӮж—Ҙеҝ—дёӯй—ҙд»¶

```typescript
import { createLogger } from "@aeron/observability";
import type { Middleware } from "@aeron/core";

export function createRequestLogger(logger: ReturnType<typeof createLogger>): Middleware {
  return async (ctx, next) => {
    const start = Date.now();
    const requestId = crypto.randomUUID();
    ctx.state.requestId = requestId;

    try {
      await next();
      logger.info("HTTP иҜ·жұӮ", {
        method: ctx.method,
        path: ctx.path,
        status: 200,
        latency: Date.now() - start,
        requestId,
      });
    } catch (err) {
      logger.error("HTTP иҜ·жұӮеӨұиҙҘ", {
        method: ctx.method,
        path: ctx.path,
        error: (err as Error).message,
        latency: Date.now() - start,
        requestId,
      });
      throw err;
    }
  };
}
```

