## дёӯй—ҙд»¶йӣҶжҲҗ

```typescript
const metricsMiddleware: Middleware = async (ctx, next) => {
  const start = Date.now();
  activeConnections.increment();

  try {
    await next();
    httpRequests.increment({
      method: ctx.method,
      path: ctx.path,
      status: "200",
    });
  } catch (err) {
    httpRequests.increment({
      method: ctx.method,
      path: ctx.path,
      status: "500",
    });
    throw err;
  } finally {
    requestLatency.observe(Date.now() - start, {
      method: ctx.method,
      path: ctx.path,
    });
    activeConnections.decrement();
  }
};
