import { AeronError, ClientError, ServerError } from "@aeron/core";
import type { Middleware } from "@aeron/core";

const errorHandler: Middleware = async (ctx, next) => {
  try {
    await next();
  } catch (err) {
    if (err instanceof AeronError) {
      return ctx.json(
        {
          error: err.message,
          code: err.code,
          ...(err instanceof ValidationError ? { details: err.details } : {})
        },
        err.statusCode
      );
    }

    // жңӘйў„жңҹзҡ„й”ҷиҜҜ
    console.error("Unhandled error:", err);
    return ctx.json({ error: "еҶ…йғЁжңҚеҠЎеҷЁй”ҷиҜҜ" }, 500);
  }
};

const app = createApp({ port: 3000 });
app.use(errorHandler); // з¬¬дёҖдёӘжіЁеҶҢпјҢжҚ•иҺ·жүҖжңүеҗҺз»ӯй”ҷиҜҜ
