## жҙӢи‘ұжЁЎеһӢ

дёӯй—ҙд»¶жҢүжіЁеҶҢйЎәеәҸжү§иЎҢпјҢдҪҶжҜҸдёӘдёӯй—ҙд»¶еҸҜд»ҘеңЁ `await next()` еүҚеҗҺеҲҶеҲ«жү§иЎҢйҖ»иҫ‘пјҡ

```typescript
// жү§иЎҢйЎәеәҸ: AеүҚ -> BеүҚ -> CеӨ„зҗҶ -> BеҗҺ -> AеҗҺ
const middlewareA: Middleware = async (ctx, next) => {
  console.log("A: before");
  await next();
  console.log("A: after");
};

const middlewareB: Middleware = async (ctx, next) => {
  console.log("B: before");
  await next();
  console.log("B: after");
};

app.use(middlewareA);
app.use(middlewareB);
app.use(async (ctx) => {
  console.log("C: handle");
  return ctx.json({ ok: true });
});
```

